-- ----------------------------
-- Procedure structure for generate_fund_announcement
-- ----------------------------
DROP PROCEDURE IF EXISTS `generate_fund_announcement`;
delimiter ;;
CREATE PROCEDURE `generate_fund_announcement`()
BEGIN
    DECLARE fund_id INT DEFAULT 1;
    DECLARE i INT;
    DECLARE title VARCHAR(200);
    DECLARE pub_date DATE;
    DECLARE titles VARCHAR(500) DEFAULT '2026年第一季度报告,关于基金分红的公告,暂停大额申购业务的公告,基金经理变更公告,2025年年度报告,更新招募说明书的公告,新增销售机构的公告,开通转换业务的公告';
    
    WHILE fund_id <= 50 DO
        SET i = 1;
        WHILE i <= 4 DO
            SET title = SUBSTRING_INDEX(SUBSTRING_INDEX(titles, ',', i + (fund_id % 4)), ',', -1);
            -- 日期随机分布在2025-06至2026-06区间
            SET pub_date = DATE_ADD('2025-06-01', INTERVAL FLOOR(RAND() * 365) DAY);
            
            VALUES (fund_id, title, pub_date);
            
            SET i = i + 1;
        END WHILE;
        
        SET fund_id = fund_id + 1;
    END WHILE;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for generate_fund_nav
-- ----------------------------
DROP PROCEDURE IF EXISTS `generate_fund_nav`;
delimiter ;;
CREATE PROCEDURE `generate_fund_nav`()
BEGIN
    DECLARE fund_id INT DEFAULT 1;
    DECLARE fund_type VARCHAR(50);
    DECLARE cur_date DATE;
    DECLARE days_count INT DEFAULT 0;
    DECLARE unit_nav DECIMAL(8,4);
    DECLARE daily_ret DECIMAL(6,2);
    DECLARE base_nav DECIMAL(8,4);
    
    -- 净值截止日期：2026-06-23，往前推260个交易日
    SET cur_date = '2026-06-23';
    
    WHILE fund_id <= 50 DO
        -- 获取基金类型
        SELECT `type` INTO fund_type FROM fund_info WHERE id = fund_id;
        
        -- 根据类型设置260天前的初始净值基准
        CASE fund_type
            WHEN '股票型' THEN SET base_nav = 1.1000;
            WHEN '混合型' THEN SET base_nav = 1.1500;
            WHEN '债券型' THEN SET base_nav = 1.0500;
            WHEN '货币型' THEN SET base_nav = 1.0000;
            WHEN '指数型' THEN SET base_nav = 1.2000;
            ELSE SET base_nav = 1.0000;
        END CASE;
        
        SET days_count = 0;
        SET unit_nav = base_nav;
        SET cur_date = '2026-06-23';
        
        -- 倒序生成260个交易日数据
        WHILE days_count < 260 DO
            -- 跳过周六周日
            IF DAYOFWEEK(cur_date) NOT IN (1,7) THEN
                -- 按基金类型生成对应幅度的日涨跌幅
                CASE fund_type
                    WHEN '股票型' THEN SET daily_ret = (RAND() * 4 - 2); -- -2% ~ +2%
                    WHEN '混合型' THEN SET daily_ret = (RAND() * 2 - 1); -- -1% ~ +1%
                    WHEN '债券型' THEN SET daily_ret = (RAND() * 0.4 - 0.1); -- -0.1% ~ +0.3%
                    WHEN '货币型' THEN SET daily_ret = (RAND() * 0.015 + 0.005); -- 0.005% ~ 0.02% 始终正收益
                    WHEN '指数型' THEN SET daily_ret = (RAND() * 5 - 2.5); -- -2.5% ~ +2.5%
                    ELSE SET daily_ret = 0;
                END CASE;
                
                -- 计算当日净值
                SET unit_nav = unit_nav * (1 + daily_ret / 100);
                
                -- 插入数据，累计净值模拟历史分红，单位净值+0.3
                VALUES (fund_id, cur_date, ROUND(unit_nav,4), ROUND(unit_nav + 0.3,4), ROUND(daily_ret,2));
                
                SET days_count = days_count + 1;
            END IF;
            -- 日期向前推1天
            SET cur_date = DATE_SUB(cur_date, INTERVAL 1 DAY);
        END WHILE;
        
        SET fund_id = fund_id + 1;
    END WHILE;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for generate_fund_sector
-- ----------------------------
DROP PROCEDURE IF EXISTS `generate_fund_sector`;
delimiter ;;
CREATE PROCEDURE `generate_fund_sector`()
BEGIN
    DECLARE fund_id INT DEFAULT 1;
    DECLARE fund_type VARCHAR(50);
    DECLARE sector_count INT;
    DECLARE i INT;
    DECLARE sector_name VARCHAR(50);
    DECLARE ratio DECIMAL(5,2);
    DECLARE total_ratio DECIMAL(5,2);
    DECLARE sectors VARCHAR(255) DEFAULT '制造业,金融业,信息技术,医药生物,电力设备,食品饮料,交通运输,房地产,煤炭,社会服务';
    
    WHILE fund_id <= 50 DO
        SELECT `type` INTO fund_type FROM fund_info WHERE id = fund_id;
        
        -- 货币型行业配置少，其他类型5-8条
        IF fund_type = '货币型' THEN
            SET sector_count = 3;
        ELSE
            SET sector_count = FLOOR(RAND() * 4 + 5);
        END IF;
        
        SET total_ratio = 0;
        SET i = 1;
        
        WHILE i <= sector_count DO
            SET sector_name = SUBSTRING_INDEX(SUBSTRING_INDEX(sectors, ',', i), ',', -1);
            SET ratio = ROUND(RAND() * 20 + 5, 2);
            SET total_ratio = total_ratio + ratio;
            
            -- 最后一条修正总占比为80%-90%，符合真实基金持仓特征
            IF i = sector_count THEN
                SET ratio = ROUND(80 + RAND() * 10 - (total_ratio - ratio), 2);
            END IF;
            
            VALUES (fund_id, sector_name, GREATEST(ratio, 1.00));
            
            SET i = i + 1;
        END WHILE;
        
        SET fund_id = fund_id + 1;
    END WHILE;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for generate_fund_stock
-- ----------------------------
DROP PROCEDURE IF EXISTS `generate_fund_stock`;
delimiter ;;
CREATE PROCEDURE `generate_fund_stock`()
BEGIN
    DECLARE fund_id INT DEFAULT 1;
    DECLARE fund_type VARCHAR(50);
    DECLARE i INT;
    DECLARE stock_name VARCHAR(50);
    DECLARE ratio DECIMAL(5,2);
    DECLARE stocks VARCHAR(500) DEFAULT '贵州茅台,宁德时代,招商银行,隆基绿能,药明康德,比亚迪,长江电力,中国平安,美的集团,海康威视,迈瑞医疗,五粮液,立讯精密,万科A,格力电器,三一重工,中国中免,恒瑞医药,亿纬锂能,紫金矿业';
    
    WHILE fund_id <= 50 DO
        SELECT `type` INTO fund_type FROM fund_info WHERE id = fund_id;
        
        -- 债券/货币型配置债券类标的，权益类配置A股股票
        IF fund_type IN ('货币型', '债券型') THEN
        ELSE
            SET i = 1;
            WHILE i <= 10 DO
                -- 按基金ID偏移取股票池，避免重复
                SET stock_name = SUBSTRING_INDEX(SUBSTRING_INDEX(stocks, ',', (fund_id + i - 1) % 20 + 1), ',', -1);
                -- 占比按名次递减，3%-10%区间
                SET ratio = ROUND(10 - i * 0.6 + RAND() * 1, 2);
                
                VALUES (fund_id, stock_name, GREATEST(ratio, 2.00));
                
                SET i = i + 1;
            END WHILE;
        END IF;
        
        SET fund_id = fund_id + 1;
    END WHILE;
END
;;
delimiter ;

SET FOREIGN_KEY_CHECKS = 1;
