INSERT INTO `fund_info` VALUES (45, '000045', '嘉实货币A', '货币型', 268.90, '2005-03-18', 5, 5, '低风险', '七天通知存款利率', '本货币基金采用稳健投资策略，配置高等级短期资产，收益平稳，流动性佳，适合低风险资金配置。');
INSERT INTO `fund_info` VALUES (46, '510300', '华泰柏瑞沪深300ETF', '指数型', 580.20, '2012-05-04', 6, 6, '中高风险', '沪深300指数', '本基金紧密跟踪沪深300指数，采用完全复制策略，跟踪误差小，费率低廉，适合宽基指数配置。');
INSERT INTO `fund_info` VALUES (47, '510500', '南方中证500ETF', '指数型', 320.60, '2013-02-06', 4, 7, '中高风险', '中证500指数', '本基金跟踪中证500指数，覆盖中小盘成长股，采用完全复制法，跟踪精度高，适合中小盘风格配置。');
INSERT INTO `fund_info` VALUES (48, '159915', '易方达创业板ETF', '指数型', 215.40, '2011-09-20', 2, 8, '中高风险', '创业板指', '本基金紧密跟踪创业板价格指数，聚焦成长型科技企业，弹性大，适合成长风格配置与交易。');
INSERT INTO `fund_info` VALUES (49, '588000', '华夏科创50ETF', '指数型', 186.90, '2020-09-28', 1, 9, '中高风险', '科创50指数', '本基金跟踪科创板50成份指数，聚焦硬科技赛道，科技属性强，波动较大，长期成长空间广阔。');
